import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './studentDashboard.css';

function StudentDashboard() {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [projectData, setProjectData] = useState({
    title: '',
    description: '',
    objectives: '',
    timeline: '',
    resources: '',
    mentorId: '',
    status: 'pending'
  });
  const [studentData, setStudentData] = useState(null);
  const [mentorData, setMentorData] = useState(null);
  const [meetings, setMeetings] = useState([]);
  const [reports, setReports] = useState([]);
  const [loading, setLoading] = useState(true);
  const [availableMentors, setAvailableMentors] = useState([]);
  const [selectedMentor, setSelectedMentor] = useState(null);
  const [requestStatus, setRequestStatus] = useState('');
  const [mentorSlots, setMentorSlots] = useState([]);
  const [selectedMentorForSlots, setSelectedMentorForSlots] = useState(null);

  // Upload state
  const [uploadType, setUploadType] = useState('report');
  const [uploadTitle, setUploadTitle] = useState('');
  const [uploadDescription, setUploadDescription] = useState('');
  const [uploadFile, setUploadFile] = useState(null);
  const [uploadStatus, setUploadStatus] = useState('');

  const [showProjectForm, setShowProjectForm] = useState(false);
  const [projectFormData, setProjectFormData] = useState({
    title: '',
    description: '',
    objectives: '',
    timeline: '',
    resources: ''
  });

  // Fetch user data on component mount
  useEffect(() => {
    const fetchUserData = async () => {
      try {
        const user = JSON.parse(localStorage.getItem('user'));
        if (!user) {
          navigate('/');
          return;
        }

        const token = localStorage.getItem('token');

        // Fetch student's data
        const res = await axios.get('http://localhost:5050/api/students/me', {
          headers: { Authorization: `Bearer ${token}` }
        });
        setStudentData(res.data);

        // Fetch student's projects
        const projectsRes = await axios.get(`http://localhost:5050/api/projects/student/${user.id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setStudentProjects(projectsRes.data);

        // Fetch student's mentor data if assigned
        if (res.data.mentorId) {
          const mentorRes = await axios.get(`http://localhost:5050/api/mentors/${res.data.mentorId}`, {
            headers: { Authorization: `Bearer ${token}` }
          });
          setMentorData(mentorRes.data);
        }

        // Fetch student's meetings
        const meetingsRes = await axios.get(`http://localhost:5050/api/meetings/student/${user.id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setMeetings(meetingsRes.data);

        // Fetch student's reports
        const reportsRes = await axios.get(`http://localhost:5050/api/reports/student/${user.id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setReports(reportsRes.data);

        // Fetch available mentors
        const mentorsRes = await axios.get('http://localhost:5050/api/mentors', {
          headers: { Authorization: `Bearer ${token}` }
        });
        setAvailableMentors(mentorsRes.data);

      } catch (error) {
        console.error("Error fetching data:", error);
        alert("Error loading dashboard. Please try again.");
      } finally {
        setLoading(false);
      }
    };

    fetchUserData();
  }, [navigate]);

  // Fetch mentor slots when selectedMentorForSlots changes
  useEffect(() => {
    if (selectedMentorForSlots) {
      const fetchSlots = async () => {
        try {
          const token = localStorage.getItem('token');
          const slotsRes = await axios.get(`http://localhost:5050/api/availability/mentor/${selectedMentorForSlots.id}`, {
            headers: { Authorization: `Bearer ${token}` }
          });
          setMentorSlots(slotsRes.data);
        } catch (error) {
          console.error("Error fetching slots:", error);
        }
      };
      fetchSlots();
    }
  }, [selectedMentorForSlots]);

  const handleRequestMentor = async () => {
    if (!selectedMentor) {
      alert("Please select a mentor to request.");
      return;
    }

    try {
      const token = localStorage.getItem('token');
      const user = JSON.parse(localStorage.getItem('user'));
      await axios.post('http://localhost:5050/api/mentor-requests', {
        studentId: user.id,
        mentorId: selectedMentor.id,
        message: 'Request for mentorship'
      }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setRequestStatus('Request sent successfully!');
    } catch (error) {
      console.error("Error requesting mentor:", error);
      setRequestStatus('Error sending request.');
    }
  };

  const handleFileChange = (e) => {
    setUploadFile(e.target.files[0]);
  };

  const handleUpload = async () => {
    if (!uploadFile || !uploadTitle) {
      alert("Please provide a title and select a file.");
      return;
    }

    try {
      const token = localStorage.getItem('token');
      const user = JSON.parse(localStorage.getItem('user'));
      const formData = new FormData();
      formData.append('file', uploadFile);
      formData.append('title', uploadTitle);
      formData.append('description', uploadDescription);
      formData.append('studentId', user.id);

      await axios.post('http://localhost:5050/api/reports', formData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setUploadStatus('Report uploaded successfully!');
      // Refresh reports
      const reportsRes = await axios.get(`http://localhost:5050/api/reports/student/${user.id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setReports(reportsRes.data);
    } catch (error) {
      console.error("Error uploading report:", error);
      setUploadStatus('Error uploading report.');
    }
  };

  const handleProjectFormChange = (e) => {
    setProjectFormData({ ...projectFormData, [e.target.name]: e.target.value });
  };

  const handleSubmitProject = async () => {
    try {
      const token = localStorage.getItem('token');
      const user = JSON.parse(localStorage.getItem('user'));
      await axios.post('http://localhost:5050/api/projects', {
        ...projectFormData,
        studentId: user.id,
        status: 'pending'
      }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setShowProjectForm(false);
      // Refresh projects
      const projectsRes = await axios.get(`http://localhost:5050/api/projects/student/${user.id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setStudentProjects(projectsRes.data);
    } catch (error) {
      console.error("Error submitting project:", error);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('user');
    localStorage.removeItem('token');
    navigate('/');
  };

  if (loading) {
    return <div>Loading...</div>;
  }

  return (
    <div className="dashboard">
      <header className="dashboard-header">
        <h1>Student Dashboard</h1>
        <button onClick={handleLogout} className="logout-btn">Logout</button>
      </header>

      <nav className="dashboard-nav">
        <button onClick={() => setActiveTab('dashboard')} className={activeTab === 'dashboard' ? 'active' : ''}>Dashboard</button>
        <button onClick={() => setActiveTab('projects')} className={activeTab === 'projects' ? 'active' : ''}>Projects</button>
        <button onClick={() => setActiveTab('meetings')} className={activeTab === 'meetings' ? 'active' : ''}>Meetings</button>
        <button onClick={() => setActiveTab('findMentors')} className={activeTab === 'findMentors' ? 'active' : ''}>Find Mentors</button>
        <button onClick={() => setActiveTab('reports')} className={activeTab === 'reports' ? 'active' : ''}>Reports</button>
      </nav>

      <div className="dashboard-content">
        {activeTab === 'dashboard' && (
          <div className="dashboard-overview">
            <h2>Welcome, {studentData?.name}</h2>
            <p>Email: {studentData?.email}</p>
            <p>Institution: {studentData?.institution}</p>
            {mentorData ? (
              <div className="mentor-info">
                <h3>Your Mentor</h3>
                <p>Name: {mentorData.name}</p>
                <p>Email: {mentorData.email}</p>
                <p>Specialties: {mentorData.specialties?.join(', ')}</p>
              </div>
            ) : (
              <p>No mentor assigned yet. Please request a mentor.</p>
            )}
          </div>
        )}

        {activeTab === 'projects' && (
          <div className="projects-section">
            <h2>Projects</h2>
            <button onClick={() => setShowProjectForm(true)}>Submit New Project</button>
            {showProjectForm && (
              <div className="project-form">
                <h3>Submit Project Proposal</h3>
                <input name="title" placeholder="Project Title" onChange={handleProjectFormChange} />
                <textarea name="description" placeholder="Description" onChange={handleProjectFormChange} />
                <textarea name="objectives" placeholder="Objectives" onChange={handleProjectFormChange} />
                <input name="timeline" placeholder="Timeline" onChange={handleProjectFormChange} />
                <input name="resources" placeholder="Resources Needed" onChange={handleProjectFormChange} />
                <button onClick={handleSubmitProject}>Submit</button>
                <button onClick={() => setShowProjectForm(false)}>Cancel</button>
              </div>
            )}
            <div className="projects-list">
              {studentProjects?.map(project => (
                <div key={project.id} className="project-card">
                  <h3>{project.title}</h3>
                  <p>{project.description}</p>
                  <p>Status: {project.status}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'meetings' && (
          <div className="meetings-section">
            <h2>Meetings</h2>
            {mentorData ? (
              <div>
                <h3>Scheduled Meetings</h3>
                <div className="meetings-list">
                  {meetings.map(meeting => (
                    <div key={meeting.id} className="meeting-card">
                      <h3>{meeting.title}</h3>
                      <p><strong>Date:</strong> {new Date(meeting.date).toLocaleDateString()}</p>
                      <p><strong>Time:</strong> {meeting.time}</p>
                      <p><strong>Location:</strong> {meeting.location}</p>
                      <p><strong>Status:</strong> {meeting.status}</p>
                    </div>
                  ))}
                </div>
              </div>
            ) : (
              <div>
                <p>No mentor assigned. Please request a mentor in the "Find Mentors" tab to schedule meetings.</p>
                <div>
                  <label htmlFor="mentorSlotSelect">Preview Slots by Mentor:</label>{' '}
                  <select id="mentorSlotSelect" value={selectedMentorForSlots?.id || ''} onChange={e => {
                    const mid = e.target.value;
                    setSelectedMentorForSlots(availableMentors.find(m => m.id === mid) || null);
                  }}>
                    <option value="">Choose Mentor</option>
                    {availableMentors.map(m => <option value={m.id} key={m.id}>{m.name}</option>)}
                  </select>
                  {selectedMentorForSlots && (
                    <div className="meetings-list" style={{ marginTop: 10 }}>
                      {mentorSlots.length === 0 ? <p>No slots for this mentor yet.</p> : mentorSlots.map(slot => (
                        <div className="meeting-card" key={slot.id}>
                          <h3>{slot.day}</h3>
                          <p><strong>Time:</strong> {slot.startTime} - {slot.endTime}</p>
                          <p><strong>Status:</strong> {slot.status}</p>
                          <span style={{ color: '#999' }}>Request a mentor to book</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        )}

        {activeTab === 'findMentors' && (
          <div className="find-mentors-section">
            <h2>Find Mentors</h2>
            <div className="mentors-list">
              {availableMentors.map(mentor => (
                <div key={mentor.id} className="mentor-card">
                  <h3>{mentor.name}</h3>
                  <p>Email: {mentor.email}</p>
                  <p>Institution: {mentor.institution}</p>
                  <p>Available Slots: {mentor.availableSlots}</p>
                  {mentor.specialties && <p>Specialties: {mentor.specialties.join(', ')}</p>}
                  <button onClick={() => setSelectedMentor(mentor)}>Request Mentor</button>
                </div>
              ))}
            </div>
            {selectedMentor && (
              <div className="request-form">
                <h3>Request Mentor: {selectedMentor.name}</h3>
                <button onClick={handleRequestMentor}>Send Request</button>
                <p>{requestStatus}</p>
              </div>
            )}
          </div>
        )}

        {activeTab === 'reports' && (
          <div className="reports-section">
            <h2>Reports</h2>
            <div className="upload-section">
              <h3>Upload Report</h3>
              <select value={uploadType} onChange={(e) => setUploadType(e.target.value)}>
                <option value="report">Report</option>
              </select>
              <input type="text" placeholder="Title" value={uploadTitle} onChange={(e) => setUploadTitle(e.target.value)} />
              <textarea placeholder="Description" value={uploadDescription} onChange={(e) => setUploadDescription(e.target.value)} />
              <input type="file" onChange={handleFileChange} />
              <button onClick={handleUpload}>Upload</button>
              <p>{uploadStatus}</p>
            </div>
            <div className="reports-list">
              {reports.map(report => (
                <div key={report.id} className="report-card">
                  <h3>{report.title}</h3>
                  <p><strong>Date:</strong> {new Date(report.date).toLocaleDateString()}</p>
                  <p><strong>Status:</strong> {report.status}</p>
                  {report.feedback && (
                    <p><strong>Feedback:</strong> {report.feedback}</p>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default StudentDashboard;
